// Router registers handlers to the router provided in the argument
func Router(r chi.Router) {
	// Middlewares

	// Grouped routes
	r.Group(external)
	r.Group(internal)
}

// external is the external chi.Router.Group routes
func external(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(5 << (10 * 2))) //5MB

	r.Group(authenticated)
	r.Group(public)
}

// Deprecated: the function will be removed 3 months after moving behind mulesoft
// authenticated is the authenticated chi.Router.Group
func authenticated(r chi.Router) {
	// Authentication middleware
	r.Use(authc.Middleware(authc.Config{
		Scope:   true,
		IDToken: true,
	}))

	// Routes
	authenticatedRoutes(r)
}

func authenticatedRoutes(r chi.Router) {
	// Routes without details
	// TODO - remove this once mobile team has removed them
	r.Post("/v4/pledge/status", handler.Wrap(pledge.RetrievePledgeStatus)) // Deprecated
	// ------------------------
	// Details-required routes
	// ------------------------
	r.Group(func(r chi.Router) {
		// BP details middleware
		r.Use(bp.DetailsByJWTMiddleware())

		// Routes

		// Charts
		r.Get("/v4/charts/{premises_id}", handler.Wrap(usage.Charts))
		r.Get("/v4/greengoals/districts", handler.Wrap(greengoals.DistrictsDynamic))
		r.Get("/v4/greengoals/targets", handler.Wrap(greengoals.TargetsDynamic))
		r.Delete("/v4/greengoals/cache", handler.Wrap(greengoals.InvalidateGreenGoalsCache))

		// SMRD
		r.Route("/v4/smrd", func(r chi.Router) {
			r.Post("/", handler.Wrap(smrd.Submit))
		})
	})
}

// public is the public chi.Router.Group routes
func public(r chi.Router) {
	// Routes
	r.Post("/v4/email/subscription", handler.Wrap(emailsubscription.Register))
	r.Get("/v4/public/greengoals/districts", handler.Wrap(greengoals.DistrictsStatic))
	r.Get("/v4/public/greengoals/charts/district", handler.Wrap(greengoals.GetDistrictConsumption))
	r.Get("/v4/public/greengoals/charts/country", handler.Wrap(greengoals.GetNationalConsumption))
	r.Get("/v4/public/greengoals/targets", handler.Wrap(greengoals.TargetsStatic))
}

// internal is the OAuth2 machine-to-machine chi.Router.Group
func internal(r chi.Router) {
	// Middlewares
	// Access token middleware
	r.Use(basiciam.RequireAccessToken(auth0.JWKSKeyFunc))
	// Audience middleware
	r.Use(basiciam.RequireClaimAudience(auth0.AudM2M))

	// Routes

	// User
	r.Route("/v4/user", func(r chi.Router) {
		// Retrieve IAM_ID from formdata
		r.Use(bp.DetailsByFormMiddleware())

		// Account details
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadAccount)).
			Get("/accounts", handler.Wrap(user.RetrieveAccounts))

		// Chart
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadChart)).
			Get("/charts/{premises_id}", handler.Wrap(usage.Charts))
	})

	// Njord Billing
	r.Route("/v4/accounts", func(r chi.Router) {
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MReadAccount))

		r.Get("/all", handler.Wrap(account.RetrieveAccountsByIAM))
		r.Get("/outstanding", handler.Wrap(account.OutstandingBySystem))
	})

	// BYOB
	r.Route("/v4/byob", func(r chi.Router) {
		// Temporarily use GraphQL scope to protect BYOB admin routes
		// TODO: Create appropriate scope/permissions on Auth0
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MReadGraphQL))

		r.Get("/redemptions/report", handler.Wrap(byob.GenerateRedemptionReport))
	})
}

